        Object.defineProperty(this, "$error", {
            enumerable: true,
            configurable: true,
            writable: true,
            value: void 0
        });
        Object.defineProperty(this, "$defaultApplied", {
            enumerable: true,
            configurable: true,
            writable: true,
            value: void 0
        });
        Object.defineProperty(this, "$gridOverlayMode", {
            enumerable: true,
            configurable: true,
            writable: true,
            value: void 0
        });
        // Computed stores
